var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"덕분에 살았군. 이건 기억해 두지.","JPN":"おかげで助かったよ、この恩は覚えておこう。","ENG":"I guess I owe you my life. I'll remember that.","TWN":"多虧你們，我才活了下來，我會記住的。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"별말씀을.","JPN":"どういたしまして。","ENG":"It was our pleasure.","TWN":"這沒什麼。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"의뢰인이 위험에 처했으면 당연히 도와드려야지.","JPN":"依頼人が危険にさらされたら、当然助けるさ。","ENG":"It's my job to help when you're in danger.","TWN":"委託人遇到危險的話，我們當然要幫忙了。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"......자네에게 한 말 아닐세, 메이슨.","JPN":"……お前に言ったんじゃないぞ、メイソン。","ENG":"I wasn't talking to you, Mason...","TWN":"……這不是對你說的，梅森。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"말이 나와서 말인데, 정보를 캐라고 보내놨더니 붙잡힌 공주님 신세나 되고, 그게 무슨 개망신인가?","JPN":"頼んだ情報を手に入れるところか、奴らに捕まるなんてな。情けないにもほどがある。","ENG":"If anything, you ended up getting captured like a damsel in distress when I sent you to collect intel. How embarrassing is that?","TWN":"我派你去收集情報，結果你卻成了被綁架的公主，這是在搞什麼啊？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"여기 숙녀 분들이 도와주지 않았다면 강가에서 변사체 같은 걸로 발견되었을 텐데.","JPN":"こちらのレディーたちが助けてくれなければ、川辺で変死体として見つかったんだろうな。","ENG":"If it weren't for these ladies, you'd be nothing more than a cold corpse by now.","TWN":"要不是這裡的淑女們救了你，你說不定就變成河邊的一具特異體屍體了。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......의뢰인 씨. 원래 현장이라는 게 꼭 예정대로 돌아가는 건 아니라고.","JPN":"……依頼人よ、現場ってもんはな、いつも予定通りまわるとは限らないんだ。","ENG":"My dear client... Things don't always go as expected in the field, you know.","TWN":"……委託人，現場人員不代表他一定能按原定計劃返回。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"자네에 대한 나의 신뢰도는 매우 예정대로 추락하고 있네.","JPN":"そうか、お前に対する俺の信頼度は予定どおり右肩下がりだな。","ENG":"Well, my trust in you sure is plummeting, as expected.","TWN":"我對你的信任，也正按原定計劃急速下降……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아니, 그래도 고생해서 여기까지 구하러 왔는데 말이야.......","JPN":"苦労してここまで助けにきてやったのに……","ENG":"After everything I've been through to come save you...","TWN":"不，可是我都為了救你來到這裡了……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"칭찬 정도는 해 줘도 되잖아.......","JPN":"褒めてくれたっていいじゃないか……","ENG":"You could at least give me a pat on the back.","TWN":"你就不能稱讚我一下嗎……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"쓸데없는 소리는 됐어.","JPN":"無駄話はこの辺にしよう。","ENG":"That's enough.","TWN":"廢話就算了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그보다 여기서 무슨 일이 벌어지고 있는 건지 설명해 줘.","JPN":"それより、ここで何が起きているのか教えてほしい。","ENG":"Now... Can you please tell us what's going on here?","TWN":"比起這個，你給我解釋一下這裡發生了什麼事。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 정도는 우리도 들을 자격이 있다고 생각하는데?","JPN":"それくらいは私たちも聞く権利があると思うけど？","ENG":"I think we deserve to hear an explanation.","TWN":"這些事情，我們也有資格聽吧？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"......물론이지.","JPN":"……もちろんだ。","ENG":"Why, of course.","TWN":"……那當然！"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"그전에 우선 내 소개부터 해야겠군.","JPN":"その前に、自己紹介をしよう。","ENG":"Let me introduce myself first.","TWN":"那在此之前我得先自我介紹一下。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"내 이름은 마크 핀리.","JPN":"俺の名前は、マーク・フィンリー。","ENG":"My name is Mark Finley.","TWN":"我的名字叫馬克·芬利。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FINLEY_CIA_NULL_BLACKBIRD","text":{"KOREA":"일단은 민간군사기업인 핀리 하이어드의 사장이지. 잘 부탁하네.","JPN":"一応、民間軍事企業であるフィンリー・ハイアードの社長だ。よろしく頼む。","ENG":"I'm the President of Finley Hired, a private military company. It's a pleasure to meet you all.","TWN":"目前是民間軍事企業芬利傭兵團的老闆，請多多指教。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_BLACKBIRD","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......당신이 그 회사 사장이라고?","JPN":"……あなたがあの会社の社長だって？","ENG":"...You're the president of the company?","TWN":"……你說你是那家公司的老闆？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};